file.content:
CAPI=2:

name : "open-logic:{{library}}:{{area}}:{{version}}"
description : "{{codebase}}; {{description}} see https://github.com/open-logic/open-logic/blob/main/doc/EntityList.md#{{area}}"

filesets:
  rtl:
    files:
    {%- for file in vhdlFiles %}
      - "{{fileDir}}{{file}}"
    {%- endfor %}
    file_type : "vhdlSource-2008"
    logical_name : "olo"
    {%- if dependencies or ext_dependencies %}
    depend :
    {%- for dep in dependencies %}
      - "^open-logic:{{library}}:{{dep}}:{{version}}"
    {%- endfor %}
    {%- for dep in ext_dependencies %}
      - "{{dep}}"
    {%- endfor %}
    {%- endif %}

  {%- if scoped_constraints %}

  scoped_constraints:
    files:
    {%- for file in tclFiles %}
      - "{{constDir}}{{file}}" : {copyto: "{{area}}/{{file}}"}
    {%- endfor %}
    {%- if tclSource %}
      - "{{constDir}}{{tclSource}}"  : {copyto: "{{area}}/{{tclSource}}", file_type: "tclSource"}
    {%- endif %}
    file_type: "user"
  {%- endif %}


targets:
  default:
    filesets :
      - "rtl"
    {%- if scoped_constraints %}
      - "tool_vivado? (scoped_constraints)"
    {%- endif %}


{%- if library == "open-logic" %}
provider:
  name    : github
  user    : open-logic
  repo    : open-logic
  version : {{version}}
{%- endif %}

CAPI=2:

name : open-logic:{{library}}:{{submodule}}:{{version}}
description : {{codebase}}; {{description}} see https://github.com/enclustra/en_cl_fix/blob/main/README.md

filesets:
  rtl:
    files:
    {%- for file in vhdlFiles %}
      - {{fileDir}}{{file}}
    {%- endfor %}
    file_type : vhdlSource-2008
    logical_name : olo

targets:
  default:
    filesets :
      - rtl

{%- if library == "open-logic" %}

provider:
  name    : github
  user    : open-logic
  repo    : en_cl_fix
  version : open-logic-{{version}}
{%- endif %}

#Automatically load all constraints
namespace eval olo_all_constraints_amd {

	variable fileLoc [file normalize [file dirname [info script]]]

	puts "OLO LOAD ALL CONSTRAINTS"

	#axi does not have constraints
	foreach area {base intf} {
		source $fileLoc/../../src/$area/tcl/olo_${area}_constraints_amd.tcl
	}
}
